queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?amenityname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasAmenities ?child ; p:hasHotels ?parent . } GROUP BY ?child }
  ?child p:amenityName ?amenityname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hotels } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?amenityname WHERE {
  ?hotel_amenities a :HotelAmenities .
  ?amenities a :Amenities .
  ?hotel_amenities p:hasAmenities ?amenities .
  ?hotels a :Hotels .
  ?hotel_amenities p:hasHotels ?hotels .
  ?hotels p:name ?name .
  ?amenities p:amenityName ?amenityname .
} }
  collective: { SELECT ?amenityname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasAmenities ?child ; p:hasHotels ?parent . } GROUP BY ?child }
  ?child p:amenityName ?amenityname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hotels } }
  FILTER(?nf = ?total)
} }
}
